"use strict";import{Children as e,isValidElement as l}from"react";import{TabsList as p}from"../TabsList";export function getTabData(i){return(e.map(i,r=>r)??[]).filter(r=>l(r)).filter(r=>r.type===p).map(r=>{const n=r.props.children;return e.map(n,(t,a)=>l(t)?{value:t.props.value,tabIndex:a}:null)}).flatMap(r=>r).filter(r=>r!=null)}
